const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const nom = body.nom;
const sujet = body.sujet;
const contenuHtml = body.contenuHtml;
const contenuText = body.contenuText;
const variables = body.variables || [];
const categorie = body.categorie;

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const variablesArray = Array.isArray(variables) ? variables.map(v => esc(v)).join(',') : '';
const variablesSql = variablesArray ? `ARRAY[${variablesArray}]` : `ARRAY[]::text[]`;

const sql = `INSERT INTO email_templates (id, tenant_id, nom, sujet, contenu_html, contenu_text, variables, categorie, created_at, updated_at) VALUES (gen_random_uuid()::uuid, ${esc(tenantId)}, ${esc(nom)}, ${esc(sujet)}, ${esc(contenuHtml)}, ${esc(contenuText)}, ${variablesSql}, ${esc(categorie)}, NOW(), NOW()) RETURNING id, tenant_id AS "tenantId", nom, sujet, contenu_html AS "contenuHtml", contenu_text AS "contenuText", variables, categorie, thumbnail, created_at AS "createdAt", updated_at AS "updatedAt"`;

return { sql };

const rows = $input.first().json;
const template = Array.isArray(rows) && rows.length > 0 ? rows[0] : {};
const formatted = {
  template: template
};
return formatted;
